// src/pages/BookingPage.jsx  (your guest-side parent — adapt filename to match yours)
import React, { useState } from 'react';
import BookingSummary, { BOOKING_TYPES, isWeekend } from '../components/BookingSummary.jsx';
import { addBooking, generateRefCode } from '../data/bookingStore.js';
import { diffDays } from '../data/bookingData.js';

const BookingPage = () => {
  const [checkIn, setCheckIn]           = useState('');
  const [checkOut, setCheckOut]         = useState('');
  const [bookingType, setBookingType]   = useState('');
  const [guests, setGuests]             = useState(1);
  const [guestName, setGuestName]       = useState('');
  const [guestContact, setGuestContact] = useState('');
  const [contactMethod, setContactMethod] = useState('email');
  const [submitted, setSubmitted]       = useState(false);
  const [refCode, setRefCode]           = useState('');

  const handleSubmit = () => {
    const typeInfo   = BOOKING_TYPES.find(t => t.id === bookingType);
    const weekend    = isWeekend(checkIn);
    const nights     = bookingType === 'overnight' && checkOut
      ? diffDays(checkIn, checkOut)
      : 1;
    const rate       = weekend ? typeInfo.weekendPrice : typeInfo.weekdayPrice;
    const total      = rate * nights;
    const resolvedCheckOut = bookingType === 'overnight' ? checkOut : checkIn;

    const booking = {
      id:             generateRefCode(),
      guestName:      guestName.trim(),
      guestContact:   guestContact.trim(),
      contactMethod,
      guests,
      checkIn,
      checkOut:       resolvedCheckOut,
      nights,
      bookingType,
      room: {         // kept for admin table compatibility
        icon: typeInfo.icon,
        name: typeInfo.name,
      },
      total,
      paid:           false,
      status:         'confirmed',
      specialRequests: '',
      createdAt:      new Date().toISOString(),
    };

    addBooking(booking);
    setRefCode(booking.id);
    setSubmitted(true);
  };

  if (submitted) {
    return (
      <div style={{ textAlign: 'center', padding: '4rem 2rem' }}>
        <div style={{ fontSize: '3rem' }}>🌸</div>
        <h2>Reservation Confirmed!</h2>
        <p>Your reference code is <strong>{refCode}</strong></p>
        <p>We'll reach out via {contactMethod} to confirm details.</p>
        <button onClick={() => {
          setSubmitted(false);
          setCheckIn(''); setCheckOut(''); setBookingType('');
          setGuests(1); setGuestName(''); setGuestContact('');
        }}>
          Make another booking
        </button>
      </div>
    );
  }

  return (
    <div>
      {/* Your calendar / guest detail form goes here — pass setCheckIn etc. */}

      <BookingSummary
        checkIn={checkIn}
        checkOut={checkOut}
        bookingType={bookingType}
        setBookingType={setBookingType}
        guests={guests}
        guestName={guestName}
        guestContact={guestContact}
        contactMethod={contactMethod}
        onSubmit={handleSubmit}
      />
    </div>
  );
};

export default BookingPage;
